  -- description
  'Тест по книге «Разговорный гипноз» Анвара Бакирова. Покажет, какие навыки коммуникативного влияния у тебя уже есть, а какие можно прокачать.',

  -- questions (25: 5 шкал × 5 вопросов, по 3 direct + 2 reverse)
  '[
    {"q":1,  "scale":"hypno_rapport",          "type":"direct",  "text":"В разговоре я замечаю темп и громкость речи собеседника и подстраиваюсь под них"},
    {"q":2,  "scale":"hypno_rapport",          "type":"direct",  "text":"Я ловлю ключевые слова собеседника — те, на которых он делает акцент — и возвращаюсь к ним в своих ответах"},
    {"q":3,  "scale":"hypno_rapport",          "type":"direct",  "text":"Мне легко поймать стиль человека — более формальный или более расслабленный — и попасть в него"},
    {"q":4,  "scale":"hypno_rapport",          "type":"reverse", "text":"Я говорю так, как мне удобно, и не слежу за тем, как говорит собеседник"},
    {"q":5,  "scale":"hypno_rapport",          "type":"reverse", "text":"Когда собеседник долго говорит, я теряю нить и думаю о своём ответе, а не о том, что он произносит"},

    {"q":6,  "scale":"hypno_suggestion_craft", "type":"direct",  "text":"Когда мне нужно донести идею, я заранее продумываю формулировку, а не говорю первое, что приходит в голову"},
    {"q":7,  "scale":"hypno_suggestion_craft", "type":"direct",  "text":"Я умею встраивать важную мысль в предложение так, что она звучит как нечто очевидное"},
    {"q":8,  "scale":"hypno_suggestion_craft", "type":"direct",  "text":"В своих аргументах я использую связки «и поэтому», «значит», «а это означает» — чтобы одно вытекало из другого"},
    {"q":9,  "scale":"hypno_suggestion_craft", "type":"reverse", "text":"В важных разговорах я говорю прямо в лоб, без обёртки"},
    {"q":10, "scale":"hypno_suggestion_craft", "type":"reverse", "text":"Мне трудно переформулировать свою мысль, если с первого раза меня не поняли"},

    {"q":11, "scale":"hypno_state_navigation", "type":"direct",  "text":"Перед сложным разговором я выбираю подход: убеждать логикой и фактами или вдохновлять эмоцией и образом"},
    {"q":12, "scale":"hypno_state_navigation", "type":"direct",  "text":"Во время разговора я держу в голове, что важнее в этот момент: захватить внимание, обойти возражения, донести главное или дать паузу"},
    {"q":13, "scale":"hypno_state_navigation", "type":"direct",  "text":"Я различаю собеседников: с одними нужны логика и статус, с другими — эмоции и образы"},
    {"q":14, "scale":"hypno_state_navigation", "type":"reverse", "text":"В разговоре я иду «куда вынесет» и редко замечаю его структуру"},
    {"q":15, "scale":"hypno_state_navigation", "type":"reverse", "text":"Если разговор пошёл не туда, мне сложно понять, в какой момент это произошло"},

    {"q":16, "scale":"hypno_resilience",       "type":"direct",  "text":"Когда мне что-то активно продают или убеждают, я замечаю конкретные приёмы — не только «давят», а именно как"},
    {"q":17, "scale":"hypno_resilience",       "type":"direct",  "text":"Я ловлю момент, когда собеседник формулирует что-то как «очевидное» то, что на самом деле спорно"},
    {"q":18, "scale":"hypno_resilience",       "type":"direct",  "text":"В новостях и рекламе я вижу подмену: вместо аргумента — эмоция, вместо факта — оценка"},
    {"q":19, "scale":"hypno_resilience",       "type":"reverse", "text":"Если авторитетный человек что-то утверждает уверенно, мне трудно удержать свою позицию"},
    {"q":20, "scale":"hypno_resilience",       "type":"reverse", "text":"Часто только постфактум я понимаю, что согласился(-лась) на то, чего на самом деле не хотел(а)"},

    {"q":21, "scale":"hypno_trance_access",    "type":"direct",  "text":"Я говорю так, что собеседник представляет картинку — образами, деталями, сенсорными подробностями, а не только абстрактно"},
    {"q":22, "scale":"hypno_trance_access",    "type":"direct",  "text":"В разговоре я могу замедлить темп и понизить голос так, чтобы собеседник настроился и стал слушать внимательнее"},
    {"q":23, "scale":"hypno_trance_access",    "type":"direct",  "text":"Я умею держать паузу после важной фразы — даю собеседнику время её прочувствовать, а не сразу заполняю тишину"},
    {"q":24, "scale":"hypno_trance_access",    "type":"reverse", "text":"Мне трудно держать внимание собеседника — он быстро отвлекается или перебивает"},
    {"q":25, "scale":"hypno_trance_access",    "type":"reverse", "text":"Я говорю ровно, одним регистром, и не меняю ритм в зависимости от того, что сейчас важнее"}
  ]'::jsonb,

  -- scales
  '[
    {"key":"hypno_rapport",          "name":"Раппорт и роль",                "order":1, "exercises":[], "radar_label":["Раппорт","и роль"]},
    {"key":"hypno_suggestion_craft", "name":"Мастерство внушений",           "order":2, "exercises":[], "radar_label":["Мастерство","внушений"]},
    {"key":"hypno_state_navigation", "name":"Выбор стратегии",               "order":3, "exercises":[], "radar_label":["Выбор","стратегии"]},
    {"key":"hypno_resilience",       "name":"Перехват инициативы",           "order":4, "exercises":[], "radar_label":["Перехват","инициативы"]},
    {"key":"hypno_trance_access",    "name":"Наведение открытости",          "order":5, "exercises":[], "radar_label":["Наведение","открытости"]}
  ]'::jsonb,

  -- scoring (НАВЫКОВЫЙ: higher_is_better, уровни Новичок→Мастер)
  '{
    "answer_range": [1, 5],
    "score_direction": "higher_is_better",
    "level_thresholds": [25, 50, 75],
    "level_labels": ["Новичок", "Развивающийся", "Уверенный", "Мастер"]
  }'::jsonb,

  -- ui_config
  '{
    "questions_per_block": 5,
